#include <stdio.h>
#include <stdbool.h>

void sort_perm(int *p) {
    // generate next permutation (lexicographic) for 4 elements
    int i = 2;
    while (i >= 0 && p[i] > p[i+1]) i--;
    if (i < 0) { p[0]=0; p[1]=1; p[2]=2; p[3]=3; return; }
    int j = 3;
    while (p[j] < p[i]) j--;
    int tmp = p[i]; p[i] = p[j]; p[j] = tmp;
    // reverse suffix
    int l = i+1, r = 3;
    while (l < r) { tmp = p[l]; p[l] = p[r]; p[r] = tmp; l++; r--; }
}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long v[4];
        for(int i=0;i<4;i++) scanf("%lld", &v[i]);
        int perm[4] = {0,1,2,3};
        bool found = false;
        long long aAns= -1, bAns = -1;
        for(int cnt=0; cnt<24 && !found; cnt++){
            long long sum = v[perm[0]];
            long long diff = v[perm[1]];
            long long prod = v[perm[2]];
            long long div = v[perm[3]];
            // a and b must be integers
            if(((sum + diff) & 1LL) || ((sum - diff) & 1LL)) { sort_perm(perm); continue; }
            long long a = (sum + diff) / 2;
            long long b = (sum - diff) / 2;
            if(a < 1 || b < 1 || a > 10000 || b > 10000) { sort_perm(perm); continue; }
            if(a * b != prod) { sort_perm(perm); continue; }
            if(b == 0) { sort_perm(perm); continue; }
            if(a / b != div) { sort_perm(perm); continue; }
            aAns = a; bAns = b; found = true;
        }
        if(found) printf("%lld %lld\n", aAns, bAns);
        else printf("-1 -1\n");
    }
    return 0;
}

