import java.io.*;
import java.util.*;

public class Main {
    private static boolean nextPerm(int[] p){
        int i = p.length - 2;
        while(i>=0 && p[i] > p[i+1]) i--;
        if(i<0) return false;
        int j = p.length - 1;
        while(p[j] < p[i]) j--;
        int tmp = p[i]; p[i] = p[j]; p[j] = tmp;
        for(int l=i+1, r=p.length-1; l<r; l++, r--){
            tmp = p[l]; p[l] = p[r]; p[r] = tmp;
        }
        return true;
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while(T-- > 0){
            StringTokenizer st = new StringTokenizer(br.readLine());
            long[] v = new long[4];
            for(int i=0;i<4;i++) v[i] = Long.parseLong(st.nextToken());
            int[] perm = {0,1,2,3};
            boolean found = false; long aAns=-1,bAns=-1;
            do{
                long sum=v[perm[0]], diff=v[perm[1]], prod=v[perm[2]], div=v[perm[3]];
                if(((sum+diff)&1L)!=0L || ((sum-diff)&1L)!=0L) continue;
                long a=(sum+diff)/2, b=(sum-diff)/2;
                if(a<1||b<1||a>10000||b>10000) continue;
                if(a*b!=prod) continue;
                if(b==0) continue;
                if(a/b!=div) continue;
                aAns=a; bAns=b; found=true; break;
            }while(nextPerm(perm));
            if(found) out.append(aAns).append(' ').append(bAns).append('\n');
            else out.append("-1 -1\n");
        }
        System.out.print(out.toString());
    }
}

