#!/usr/bin/env python3
import sys, itertools

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        vals = [int(next(it)) for _ in range(4)]
        found = False
        for perm in itertools.permutations(range(4)):
            s, d, p, q = (vals[perm[0]], vals[perm[1]], vals[perm[2]], vals[perm[3]])
            if (s + d) & 1: continue
            if (s - d) & 1: continue
            a = (s + d) // 2
            b = (s - d) // 2
            if not (1 <= a <= 10000 and 1 <= b <= 10000):
                continue
            if a * b != p:
                continue
            if b == 0:
                continue
            if a // b != q:
                continue
            out_lines.append(f"{a} {b}")
            found = True
            break
        if not found:
            out_lines.append("-1 -1")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    solve()

